mapper.select:
SELECT /* 1. 제목 및 데이터 기준 ID 설정 */
'전 노선 운영현황' AS linetitle, NULL AS station_id
(SELECT line_name || ' 운영현황' FROM storage.local_amenities WHERE station_id = #{station_id} LIMIT 1) AS linetitle, #{station_id} AS station_id
,
/* 2. 전체 노선 수 및 전체 역 수 */ (SELECT COUNT(DISTINCT line_name) FROM storage.local_amenities) AS linetotal, (SELECT COUNT(*) FROM storage.local_amenities) AS stationtotal,
/* 해당 호선별 역 개수 */
(SELECT COUNT(*) FROM storage.local_amenities WHERE SUBSTRING(station_id, 1, 1) = SUBSTRING(#{station_id}, 1, 1))
0 AS line_stationcount,
/* 3. 현재 미해결 장애 건수 (담당역 1:1 매칭으로 수정) */ (SELECT COUNT(*) FROM storage.incident WHERE incident_status IN ('1', '2')
AND incident_station_id = #{station_id}
) AS incident_count,
/* 4. 총 물품보관함 개수 (호선 기준) */ COALESCE(( SELECT SUM(li.local_small + li.local_middle + li.local_large) FROM storage.locker_inventory li JOIN storage.local l ON li.local_id = l.local_id
WHERE SUBSTRING(l.station_id, 1, 1) = SUBSTRING(#{station_id}, 1, 1)
), 0) AS total_lockers,
/* 5. 사용 중인 물품보관함 개수 (호선 기준) */ COALESCE(( SELECT SUM((li.local_small + li.local_middle + li.local_large) - (lu.able_small + lu.able_middle + lu.able_large)) FROM storage.locker_inventory li LEFT JOIN ( SELECT DISTINCT ON (local_id) * FROM storage.locker_usage ORDER BY local_id, observed_at DESC ) lu ON li.local_id = lu.local_id JOIN storage.local l ON li.local_id = l.local_id
WHERE SUBSTRING(l.station_id, 1, 1) = SUBSTRING(#{station_id}, 1, 1)
), 0) AS used_lockers,
/* 6. 시간대별 사용률(평균) */ COALESCE(( SELECT ROUND(AVG(((li.local_small + li.local_middle + li.local_large) - (lu.able_small + lu.able_middle + lu.able_large))::numeric / NULLIF((li.local_small + li.local_middle + li.local_large), 0) * 100), 1) FROM storage.locker_inventory li JOIN ( SELECT DISTINCT ON (local_id) * FROM storage.locker_usage ORDER BY local_id, observed_at DESC ) lu ON li.local_id = lu.local_id JOIN storage.local l ON li.local_id = l.local_id
WHERE SUBSTRING(l.station_id, 1, 1) = SUBSTRING(#{station_id}, 1, 1)
), 0) AS hour_usedlocker

SELECT TO_CHAR(days.day, 'MM/DD') as "date", COUNT(i.incident_id) as "count" FROM ( /* 오늘부터 6일 전까지의 날짜 시퀀스 생성 */ SELECT generate_series(CURRENT_DATE - INTERVAL '6 days', CURRENT_DATE, '1 day')::date as day ) days LEFT JOIN storage.incident i ON DATE(i.create_at) = days.day
/* 담당자 권한일 때 해당 호선(첫자리) 데이터만 필터링 */ AND SUBSTRING(i.incident_station_id, 1, 1) = SUBSTRING(#{station_id}, 1, 1)
GROUP BY days.day ORDER BY days.day ASC
